from flask import Flask, jsonify, request
import re

app = Flask(__name__)

@app.route('/wrap', methods=['POST'])
def wrap_input():
    if not request.is_json:
        return jsonify({'error': 'Request must be JSON'}), 400

    data = request.get_json(silent=True)
    if 'input' not in data:
        return jsonify({'error': 'Missing "input" parameter'}), 400

    input_data = data['input']

    # Input validation
    if not isinstance(input_data, str):
        return jsonify({'error': 'Invalid type for "input", expected string'}), 400

    # Allowlist validation
    if not re.match(r'^[a-zA-Z0-9]+$', input_data):
        return jsonify({'error': 'Invalid characters in "input" parameter'}), 400

    return jsonify({'html': f'<p>{input_data}</p>'})

if __name__ == '__main__':
    app.run()

